import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { useNavigate } from 'react-router-dom';
import L from 'leaflet';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import { ordersAPI } from '../../api';
import styles from './DeliveryPage.module.css';

// Фикс иконки Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl:       'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl:     'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

// Кастомная иконка маркера
const cherryIcon = new L.DivIcon({
  className: '',
  html: '<div style="font-size:36px;filter:drop-shadow(0 2px 4px rgba(0,0,0,0.3))">🍒</div>',
  iconSize:   [36, 36],
  iconAnchor: [18, 36],
});

// Компонент для обработки кликов по карте
function MapClickHandler({ onLocationSelect }) {
  useMapEvents({
    click(e) {
      onLocationSelect(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
}

export default function DeliveryPage() {
  const { user }                = useAuth();
  const { items, totalPrice, clearCart } = useCart();
  const navigate                = useNavigate();

  const [lat, setLat]     = useState(user?.last_lat     || 55.7558);
  const [lng, setLng]     = useState(user?.last_lng     || 37.6173);
  const [address, setAddress] = useState(user?.last_address || '');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(null);
  const [error, setError]     = useState('');

  const handleMapClick = (newLat, newLng) => {
    setLat(newLat);
    setLng(newLng);
    // Простое геокодирование — в MVP просто выводим координаты
    setAddress(`${newLat.toFixed(5)}, ${newLng.toFixed(5)}`);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!address.trim()) {
      setError('Укажите адрес доставки');
      return;
    }
    if (items.length === 0) {
      setError('Корзина пуста');
      return;
    }

    setLoading(true);
    setError('');

    try {
      const orderItems = items.map((i) => ({
        product_id: i.id,
        name:       i.name,
        price:      i.price,
        quantity:   i.quantity,
      }));

      const { data } = await ordersAPI.create({
        items:            orderItems,
        delivery_address: address,
        delivery_lat:     lat,
        delivery_lng:     lng,
      });

      setSuccess(data);
      clearCart();
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка оформления заказа');
    } finally {
      setLoading(false);
    }
  };

  // Экран успеха
  if (success) {
    return (
      <div className={styles.successScreen}>
        <div className={styles.successCard}>
          <div className={styles.successIcon}>🍒</div>
          <h2 className={styles.successTitle}>Заказ оформлен!</h2>
          <p className={styles.successSub}>
            Ваш заказ #{success.order.id.slice(-6).toUpperCase()} принят в обработку
          </p>

          <div className={styles.deliveryTimer}>
            <span className={styles.timerIcon}>⏱️</span>
            <div>
              <p className={styles.timerLabel}>Ожидаемое время доставки</p>
              <p className={styles.timerValue}>
                {success.delivery_minutes} минут
              </p>
            </div>
          </div>

          <div className={styles.orderInfo}>
            <div className={styles.orderInfoRow}>
              <span>Адрес</span>
              <span>{success.order.delivery_address}</span>
            </div>
            <div className={styles.orderInfoRow}>
              <span>Сумма</span>
              <span>{success.order.total_price.toLocaleString('ru-RU')} ₽</span>
            </div>
          </div>

          <div className={styles.successActions}>
            <button
              className="btn btn-cherry"
              onClick={() => navigate('/profile')}
            >
              Мои заказы
            </button>
            <button
              className="btn btn-outline"
              onClick={() => navigate('/catalog')}
            >
              Продолжить покупки
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className="container">
        <h1 className="section-title" style={{ marginBottom: 8 }}>Оформление заказа</h1>
        <p className="section-subtitle">
          Выберите точку доставки на карте или введите адрес вручную
        </p>

        <div className={styles.layout}>
          {/* Карта */}
          <div className={styles.mapSection}>
            <div className={styles.mapWrap}>
              <MapContainer
                center={[lat, lng]}
                zoom={12}
                className={styles.map}
              >
                <TileLayer
                  url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                  attribution='© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
                />
                <MapClickHandler onLocationSelect={handleMapClick} />
                <Marker position={[lat, lng]} icon={cherryIcon} />
              </MapContainer>
            </div>
            <p className={styles.mapHint}>
              🍒 Кликните по карте, чтобы выбрать точку доставки
            </p>
          </div>

          {/* Форма */}
          <form className={styles.form} onSubmit={handleSubmit}>
            <h2 className={styles.formTitle}>Детали доставки</h2>

            {/* Адрес */}
            <div className={styles.field}>
              <label className={styles.label}>Адрес доставки</label>
              <input
                type="text"
                className={styles.input}
                placeholder="Введите адрес или выберите на карте"
                value={address}
                onChange={(e) => setAddress(e.target.value)}
              />
            </div>

            {/* Координаты */}
            <div className={styles.coordsRow}>
              <div className={styles.field}>
                <label className={styles.label}>Широта</label>
                <input
                  type="number"
                  className={styles.input}
                  value={lat.toFixed(5)}
                  readOnly
                />
              </div>
              <div className={styles.field}>
                <label className={styles.label}>Долгота</label>
                <input
                  type="number"
                  className={styles.input}
                  value={lng.toFixed(5)}
                  readOnly
                />
              </div>
            </div>

            {/* Состав заказа */}
            <div className={styles.orderSummary}>
              <h3 className={styles.summaryHead}>Ваш заказ</h3>
              {items.map((item) => (
                <div key={item.id} className={styles.summaryItem}>
                  <span>{item.name} × {item.quantity}</span>
                  <span>{(item.price * item.quantity).toLocaleString('ru-RU')} ₽</span>
                </div>
              ))}
              <div className={styles.summaryTotal}>
                <span>Итого</span>
                <span>{totalPrice.toLocaleString('ru-RU')} ₽</span>
              </div>
            </div>

            {error && <p className={styles.error}>{error}</p>}

            <button
              type="submit"
              className={`btn btn-cherry ${styles.submitBtn}`}
              disabled={loading}
            >
              {loading ? 'Оформляем...' : '🍒 Оформить заказ'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
